1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	
4	const BASE_PREMIUM: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	type Item = { type: string; material?: string; enchantment?: number; cursed?: boolean };
14	type Damage = { itemType: string; amount: number };
15	type Incident = { cause: string; damages: Damage[] };
16	type QuoteStep = { op: "quote"; items: Item[] };
17	type ClaimStep = { op: "claim"; policy: number; incident: Incident };
18	type Step = QuoteStep | ClaimStep;
19	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
20	type QuoteResult = { premium: number };
21	type ClaimResult = { payout: number; remainingCap: number };
22	type StepResult = QuoteResult | ClaimResult;
23	type ScenarioResult = { results: StepResult[] };
24	
25	const INSURANCE_VALUE: Record<string, number> = {
26	  sword: 1000,
27	  amulet: 600,
28	  staff: 800,
29	  potion: 400,
30	  rune: 250,
31	  moonstone: 250,
32	};
33	
34	const DEDUCTIBLE = 100;
35	const CAP_MULTIPLIER = 2;
36	
37	const COMPONENT_BLOCK_SIZE = 3;
38	const COMPONENT_BLOCK_PREMIUM = 60;
39	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
40	
41	const itemBasePremium = (item: Item): number => BASE_PREMIUM[item.type];
42	
43	const groupByType = (items: Item[]): Map<string, Item[]> => {
44	  const groups = new Map<string, Item[]>();
45	  for (const item of items) {
46	    const bucket = groups.get(item.type) ?? [];
47	    bucket.push(item);
48	    groups.set(item.type, bucket);
49	  }
50	  return groups;
51	};
52	
53	const groupBasePremium = (type: string, group: Item[]): number => {
54	  if (COMPONENT_TYPES.has(type) && group.length === COMPONENT_BLOCK_SIZE) {
55	    return COMPONENT_BLOCK_PREMIUM;
56	  }
57	  return group.reduce((sum, item) => sum + itemBasePremium(item), 0);
58	};
59	
60	const policyBasePremium = (items: Item[]): number =>
61	  Array.from(groupByType(items).entries()).reduce(
62	    (total, [type, group]) => total + groupBasePremium(type, group),
63	    0,
64	  );
65	
66	const CURSE_SURCHARGE_RATE = 0.5;
67	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
68	const HIGH_ENCHANTMENT_THRESHOLD = 5;
69	const LOYALTY_DISCOUNT_RATE = 0.2;
70	const LOYALTY_YEARS_THRESHOLD = 2;
71	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
72	
73	type Customer = { yearsWithMHPCO: number };
74	
75	const curseSurcharge = (item: Item): number =>
76	  item.cursed ? itemBasePremium(item) * CURSE_SURCHARGE_RATE : 0;
77	
78	const highEnchantmentSurcharge = (item: Item): number =>
79	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
80	    ? itemBasePremium(item) * HIGH_ENCHANTMENT_SURCHARGE_RATE
81	    : 0;
82	
83	const itemSurcharges = (items: Item[]): number =>
84	  items.reduce(
85	    (sum, item) => sum + curseSurcharge(item) + highEnchantmentSurcharge(item),
86	    0,
87	  );
88	
89	const quotePremium = (
90	  items: Item[],
91	  customer: Customer,
92	  isFollowUp: boolean,
93	): number => {
94	  const basePremium = policyBasePremium(items);
95	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
96	  const loyaltyDiscount =
97	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
98	      ? basePremium * LOYALTY_DISCOUNT_RATE
99	      : 0;
100	  const followUpDiscount = isFollowUp ? basePremium * FOLLOW_UP_DISCOUNT_RATE : 0;
101	  return (
102	    basePremium +
103	    itemSurcharges(items) +
104	    firstInsuranceSurcharge -
105	    loyaltyDiscount -
106	    followUpDiscount +
107	    PROCESSING_FEE
108	  );
109	};
110	
111	const policyInsuranceSum = (items: Item[]): number =>
112	  items.reduce((sum, item) => sum + INSURANCE_VALUE[item.type], 0);
113	
114	const claimPayout = (damages: Damage[]): number =>
115	  damages.reduce((sum, d) => sum + (d.amount - DEDUCTIBLE), 0);
116	
117	export const runScenario = (scenario: Scenario): ScenarioResult => {
118	  let quoteCount = 0;
119	  const policies: Item[][] = [];
120	  const results: StepResult[] = scenario.steps.map((step) => {
121	    if (step.op === "quote") {
122	      const isFollowUp = quoteCount > 0;
123	      quoteCount += 1;
124	      policies.push(step.items);
125	      return {
126	        premium: Math.ceil(quotePremium(step.items, scenario.customer, isFollowUp)),
127	      };
128	    }
129	    const items = policies[step.policy];
130	    const payout = claimPayout(step.incident.damages);
131	    const cap = policyInsuranceSum(items) * CAP_MULTIPLIER;
132	    return { payout, remainingCap: cap - payout };
133	  });
134	  return { results };
135	};
