const claimPayout = (damages: Damage[]): number =>
  damages.reduce((sum, d) => sum + (d.amount - DEDUCTIBLE), 0);

const policyCap = (items: Item[]): number =>
  policyInsuranceSum(items) * CAP_MULTIPLIER;

const settleClaim = (items: Item[], incident: Incident): ClaimResult => {
  const payout = claimPayout(incident.damages);
  return { payout, remainingCap: policyCap(items) - payout };
};

const quoteForPolicy = (
  items: Item[],
  customer: Customer,
  isFollowUp: boolean,
): QuoteResult => ({
  premium: Math.ceil(quotePremium(items, customer, isFollowUp)),
});

export const runScenario = (scenario: Scenario): ScenarioResult => {
  const policies: Item[][] = [];
  const results: StepResult[] = scenario.steps.map((step) => {
    if (step.op === "quote") {
      const isFollowUp = policies.length > 0;
      policies.push(step.items);
      return quoteForPolicy(step.items, scenario.customer, isFollowUp);
    }
    return settleClaim(policies[step.policy], step.incident);
  });
  return { results };
};
